import Foundation
func isNumber(_ s: String) -> Bool { let chars = Array(s); var seenDigit=false, seenDot=false, seenExp=false, digitAfterExp=true; for i in chars.indices { let ch = chars[i]; if ch >= "0" && ch <= "9" { seenDigit=true; if seenExp { digitAfterExp=true } } else if ch == "+" || ch == "-" { if i != 0 && chars[i-1] != "e" && chars[i-1] != "E" { return false } } else if ch == "." { if seenDot || seenExp { return false }; seenDot=true } else if ch == "e" || ch == "E" { if seenExp || !seenDigit { return false }; seenExp=true; digitAfterExp=false } else { return false } }; return seenDigit && digitAfterExp }
let lines = String(data: FileHandle.standardInput.readDataToEndOfFile(), encoding: .utf8)?.split(separator: "\n", omittingEmptySubsequences: false).map { String($0).replacingOccurrences(of: "\r", with: "") } ?? []
if !lines.isEmpty { let t = Int(lines[0].trimmingCharacters(in: .whitespacesAndNewlines)) ?? 0; var out:[String]=[]; for i in 0..<t { out.append(isNumber(lines[i+1]) ? "true" : "false") }; print(out.joined(separator: "\n"), terminator: "") }
